<span class="line"><span style="color:#A6E3A1;">                &quot;true&quot;</span><span style="color:#94E2D5;"> |</span><span style="color:#A6E3A1;"> &quot;1&quot;</span><span style="color:#94E2D5;"> |</span><span style="color:#A6E3A1;"> &quot;yes&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Value</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Bool</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;">true</span><span style="color:#9399B2;">)),</span></span>
