<span class="line"><span style="color:#CBA6F7;">            if</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">recovery_attempts </span><span style="color:#94E2D5;">&lt;</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">:</span></span>
